tasks.solution:
stage('Deploy to EKS') {
    steps {
        sh """
          # Step 1: authenticate kubectl to the EKS cluster
          aws eks update-kubeconfig --region ${AWS_REGION} --name ${CLUSTER}

          # Step 2: update the container image
          kubectl set image deployment/my-app \\
            my-app=${REGISTRY}/${ECR_REPO}:${IMAGE_TAG}

          # Step 3: wait for the rollout (fail if it takes longer than 120s)
          kubectl rollout status deployment/my-app --timeout=120s
        """
    }
}

